class Solution:
    def magicalString(self, n: int) -> int:
        s = [1, 2, 2]
        p = 2
        while len(s) < n:
            count = s[p]
            num = 3 - s[-1]
            s.extend([num] * count)
            p += 1
        return s[:n].count(1)
